import { Injectable } from '@angular/core';
import { HttpClient } from '@angular/common/http';
import { AppConstants } from 'src/app/shared/config/app.constant';
import { BehaviorSubject, Observable } from 'rxjs';
import { User } from '../models/users';

export const API_URL = AppConstants.baseURL;
export const rolepermission = AppConstants.baseURL + '/rolePermission';
//export const rolepermission1 = AppConstants.baseURL + '/fmsRoles';
//export const API_URL = 'http://192.168.0.142:8010';
//export const API_URL = 'http://localhost:8010';
//export const API_URL = 'http://192.168.0.113:8010';


@Injectable({
  providedIn: 'root'
})
export class UsersService {


  constructor(private http: HttpClient) { }

  private paramSource = new BehaviorSubject({});
    getNavParam = this.paramSource.asObservable();
    
     sendNavParam(params: object) {
      this.paramSource.next(params)
    }

  getRoleScreenPermission(userId: string, screenName: string, roleName: string): Observable<any> {
    return this.http.get(`${rolepermission}/getRolePermission/${userId}/${screenName}/${roleName}`)

  }

  getUserAuditService(userId: string) {
    return this.http.get<User>(`${API_URL}/users/getModifiedUser/${userId}`);
  }

  getUserObjModified(userId: string) {
    return this.http.get<User>(`${API_URL}/users/getModifiedUser/${userId}`);
  }

  createUserService(user: User) {
    return this.http.post<boolean>(`${API_URL}/users/createUser`, user);
  }
  modifyUserService(user: User) {
    return this.http.post<boolean>(`${API_URL}/users/modifyUser`, user);
  }
  getAllUsersListService() {
    return this.http.get<User[]>(`${API_URL}/users/getAllUsers`);
  }
  getAllRoleNameService() {
    return this.http.get<string[]>(`${API_URL}/users/getAllRoleNames`);
  }
  getAllRoleNameServiceU() {
    return this.http.get<string[]>(`${API_URL}/users/getAllRoleNamesU`);
  }
  getAllAuthRole() {
    return this.http.get<any>(`${API_URL}/fmsRoles/fetchAllRolesSummary`);
  }
  // audit log starts
  onClickOfAuthOfUsers(authUser: User) {
    return this.http.get<string[]>(`${API_URL}/users/getAllRoleNames`);

  }
  onClickOfOpenOfUsers() {

  }
  // Audit log  ends for User creatrion

  // -------------------User Modification-------------
  // audit log for User Modification Starts

  onClickOfAuthOfModifyUsers(userId: string, makerId: string) {
    return this.http.get<boolean>(`${API_URL}/users/authorizeUser/${userId}/${makerId}`)
  }
  onClickOfCloseOfModifyUsers(userId: string, makerId: string) {
    return this.http.get<boolean>(`${API_URL}/users/closeUser/${userId}/${makerId}`)
  }
  onClickOfReopenOfModifyUser(userId: string, makerId: string) {
    return this.http.get<boolean>(`${API_URL}/users/reopenUser/${userId}/${makerId}`)
  }
  onClickOfDeleteOfModifyUser(userobjForDelete: any) {
    return this.http.get<boolean>(`${API_URL}/users/deleteUser/${userobjForDelete}`)
  }
  statusChangeUser(user_id) {
    return this.http.get<any>(`${API_URL}/users/statusUser/${user_id}`)
  }
  refreshGl() {
    return this.http.get<any>(`${API_URL}/refxch`);
  }
}
